class RAGState(TypedDict):
    question: str
    documents: list[str]
    is_sufficient: bool
    answer: str

def retrieve(state: RAGState) -> dict:
    docs = vector_store.similarity_search(state["question"], k=3)
    return {"documents": [d.page_content for d in docs]}

def grade(state: RAGState) -> dict:
    relevant = [d for d in state["documents"] if is_relevant(d)]
    return {"documents": relevant, "is_sufficient": len(relevant) >= 2}

def generate(state: RAGState) -> dict:
    context = "\n".join(state["documents"])
    answer = llm.invoke(f"Answer: {state['question']}\nContext: {context}")
    return {"answer": answer}
